import{_ as a,c as l,o as i,a4 as e}from"./chunks/framework.nQaBHiNx.js";const b=JSON.parse('{"title":"第七章 面向对象技术","description":"","frontmatter":{"permalink":"/basic/ruankao/software-designer/07-object-oriented-technology.html"},"headers":[],"relativePath":"computer/ruankao/software-designer/07-第七章 面向对象技术.md","filePath":"computer/ruankao/software-designer/07-第七章 面向对象技术.md"}'),o={name:"computer/ruankao/software-designer/07-第七章 面向对象技术.md"},r=e('<h1 id="第七章-面向对象技术" tabindex="-1">第七章 面向对象技术 <a class="header-anchor" href="#第七章-面向对象技术" aria-label="Permalink to &quot;第七章 面向对象技术&quot;">​</a></h1><p>客观世界由许多具体的事物、事件、概念和规则组成，这些均可被看成对象。</p><h2 id="_7-1-面向对象基础" tabindex="-1">7.1 面向对象基础 <a class="header-anchor" href="#_7-1-面向对象基础" aria-label="Permalink to &quot;7.1 面向对象基础&quot;">​</a></h2><h3 id="_7-1-1-面向对象的基础概念" tabindex="-1">7.1.1 面向对象的基础概念 <a class="header-anchor" href="#_7-1-1-面向对象的基础概念" aria-label="Permalink to &quot;7.1.1 面向对象的基础概念&quot;">​</a></h3><p>Peter Coad 和 Edward Yourdon 提出用下面的等式识别面向对象方法。</p><p>$$ 面向对象=对象+分类+继承+通过消息的通信 $$</p><ol><li>对象。在面向对象的系统中，对象是基本的运行时的实体。</li><li>消息。对象之间进行通信的一种构造叫做消息。</li><li>类。一个类定义了一组大体上相似的对象。</li><li>继承。继承是父类和子类之间共享数据和方法的机制</li><li>多态。在收到消息时，对象要予以响应。不同的对象收到同一消息可以产生完全不同的结果。</li><li>动态绑定。绑定是一种把过程调用和响应调用所需执行的代码加以结合的过程。</li></ol><h3 id="_7-1-2-面向对象分析" tabindex="-1">7.1.2 面向对象分析 <a class="header-anchor" href="#_7-1-2-面向对象分析" aria-label="Permalink to &quot;7.1.2 面向对象分析&quot;">​</a></h3><p>同其他分析方法一样，面向对象分析 (OOA) 的目的是为了获得对应应用问题的理解。理解的目的是确定系统的功能、性能要求。</p><ol><li>认定对象</li><li>组织对象</li><li>对象间的相互作用</li><li>基于对象的操作</li></ol><h3 id="_7-1-3-面向对象设计" tabindex="-1">7.1.3 面向对象设计 <a class="header-anchor" href="#_7-1-3-面向对象设计" aria-label="Permalink to &quot;7.1.3 面向对象设计&quot;">​</a></h3><h4 id="_7-1-3-1-面向对象设计的活动" tabindex="-1">7.1.3.1 面向对象设计的活动 <a class="header-anchor" href="#_7-1-3-1-面向对象设计的活动" aria-label="Permalink to &quot;7.1.3.1 面向对象设计的活动&quot;">​</a></h4><p>OOD 在复用 OOA 模型的基础上，包含与 OOA 对应如下五个活动。</p><ol><li>识别类及对象</li><li>定义属性</li><li>定义服务</li><li>识别关系</li><li>识别包</li></ol><h4 id="_7-3-1-2-面向对象设计的原则" tabindex="-1">7.3.1.2 面向对象设计的原则 <a class="header-anchor" href="#_7-3-1-2-面向对象设计的原则" aria-label="Permalink to &quot;7.3.1.2 面向对象设计的原则&quot;">​</a></h4><ol><li>单一责任原则 (Single Responsibility Principle) 。就一个类而言，应该仅有一个引起它变化的原因。</li><li>开闭原则 (Open &amp; Close Principle) 。软件实体应该是可以扩展的，即开放的；但是不可修改的，即封闭的。</li><li>里氏替换原则 (Liskov Subsitution Principle) 。子类必须能够替换掉他们的基类。</li><li>接口分离原则 (Interface Segregation Principle) 。不应该强迫客户依赖于他们不用的方法。</li><li>依赖倒置原则 (Dependence Inversion Principle) 。抽象不应该依赖于细节，细节应该依赖于抽象。</li></ol><h3 id="_7-1-4-面向对象程序设计" tabindex="-1">7.1.4 面向对象程序设计 <a class="header-anchor" href="#_7-1-4-面向对象程序设计" aria-label="Permalink to &quot;7.1.4 面向对象程序设计&quot;">​</a></h3><p>面向对象程序设计的实质是使用一种面向对象程序设计语言，采用对象、类及其相关概念所进行的程序设计。</p><ol><li>类。</li><li>继承和类层次结构。</li><li>对象、消息传递和方法。</li><li>对象自身引用。对象自身引用是 OOPL 中的一种特有结构。</li><li>重置 (Overriding) 。是在子类中重写定义父类中以及定义的方法</li><li>类属类</li><li>无实例的类</li></ol><h3 id="_7-1-5-面向对象测试" tabindex="-1">7.1.5 面向对象测试 <a class="header-anchor" href="#_7-1-5-面向对象测试" aria-label="Permalink to &quot;7.1.5 面向对象测试&quot;">​</a></h3><p>一般来说，对面向对象软件的测试可分为下列 4 个层次进行。</p><ol><li>算法层。测试类中定义的每个方法，基本上相当于传统软件测试中的单元测试。</li><li>类层。测试封装在同一个类中的所有方法与属性之间的相互作用。</li><li>模板层。测试一组协同工作的类之间的相互作用，大体上相当于传统软件测试中的集成测试。</li><li>系统层。把各个子系统组装成完整的面向对象软件系统，大体上相当于传统软件测试中的集成测试。</li></ol><h2 id="_7-2-uml" tabindex="-1">7.2 UML <a class="header-anchor" href="#_7-2-uml" aria-label="Permalink to &quot;7.2 UML&quot;">​</a></h2><p>统一建模语言是面向对象软件的标准化建模语言。由于其简单、统一，又能够表达软件设计中的动态和静态信息，目前已经成为可视化建模语言事实上的工业标准。</p><p>UML 的词汇表包含 3 种构造块：事物、关系和图。事物是对模型中最具有代表性的成分的轴向；关系把事物结合在一起；图聚集了相关的事物。</p><h3 id="_7-2-1-事物" tabindex="-1">7.2.1 事物 <a class="header-anchor" href="#_7-2-1-事物" aria-label="Permalink to &quot;7.2.1 事物&quot;">​</a></h3><p>UML 中有 4 种事物：结构事物、行为事物、分组事物和注释事物。</p><ol><li>结构事物。结构事物是 UML 模型中的名词。它们通常是模型的静态部分，描述概念或物理元素。</li><li>行为事物。行为事物是 UML 模型的动态部分。他们是模型中的动词，描述了跨越时间和空间的行为。</li><li>分组事物。分组事物是 UML 模型的组织部分，是一些由模型分解成的“盒子”。</li><li>注释事物。注释事物是 UML 模型的解释部分。这些注释事物用来描述、说明和标注模型的任何元素。</li></ol><h3 id="_7-2-2-关系" tabindex="-1">7.2.2 关系 <a class="header-anchor" href="#_7-2-2-关系" aria-label="Permalink to &quot;7.2.2 关系&quot;">​</a></h3><p>UML 中有 4 种关系：依赖、关联、泛化和实现。</p><ol><li>依赖。依赖是两个事物间的语义关系，其中一个事物发生变化会影响另一个事物的语义。</li><li>关联。关联是一种结构关系，它描述了一组链，链是对象之间的连接。</li><li>泛化。泛化是一种特殊/一般关系，特殊元素的对象可替代一般元素的对象。</li><li>实现。实现是类元之间的语义关系，其中一种类元指定了一种由另一个类元保证执行的契约。</li></ol><h3 id="_7-2-3-uml-中的图" tabindex="-1">7.2.3 UML 中的图 <a class="header-anchor" href="#_7-2-3-uml-中的图" aria-label="Permalink to &quot;7.2.3 UML 中的图&quot;">​</a></h3><p>图是一组元素的图形表示，大多数情况下把图画成顶点和弧的连通图。</p><p>UML 2.0 提供了 13 种图，分别是类图、对象图、用例图、序列化、通信图、状态图、活动图、构件图、组合结构图、部署图、包图、交互概览图和计时器。序列图、通信图、交互概览图和计时图均被称为交互图。</p><ol><li>类图</li><li>对象图</li><li>用例图</li><li>交互图</li><li>状态</li><li>活动图</li><li>构件图</li><li>组合结构图</li><li>部署图</li><li>包图</li></ol><h2 id="_7-3-设计模式" tabindex="-1">7.3 设计模式 <a class="header-anchor" href="#_7-3-设计模式" aria-label="Permalink to &quot;7.3 设计模式&quot;">​</a></h2><h3 id="_7-3-1-设计模式的要素" tabindex="-1">7.3.1 设计模式的要素 <a class="header-anchor" href="#_7-3-1-设计模式的要素" aria-label="Permalink to &quot;7.3.1 设计模式的要素&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>“每一个模式描述了一个在我们周围不断重复发生的问题，以及该问题的解决方案的核心。这样，你就能一次又一次地使用该方案而不必做重复劳动。”</p></div><p>设计模式一般有以下 4 个基本要素。</p><ol><li>模式名称。一个助记名，它用一两个词来描述模式的问题、解决方案和效果。模式名可以帮助人们思考便于人们与其他人交流设计思想及设计结果。</li><li>问题。问题描述了应该在何时使模式。它解释了设计问题和问题存在的前因后果，可能描述了特定的设计问题。</li><li>解决方案。解决方案描述了设计的组成成分、它们之间的相互关系及各自的职责和协作方式。</li><li>效果。效果描述了模式应用的效果及使用模式应权衡的问题。</li></ol><h3 id="_7-3-2-创建型设计模式" tabindex="-1">7.3.2 创建型设计模式 <a class="header-anchor" href="#_7-3-2-创建型设计模式" aria-label="Permalink to &quot;7.3.2 创建型设计模式&quot;">​</a></h3><h3 id="_7-3-3-结构型设计模式" tabindex="-1">7.3.3 结构型设计模式 <a class="header-anchor" href="#_7-3-3-结构型设计模式" aria-label="Permalink to &quot;7.3.3 结构型设计模式&quot;">​</a></h3><h3 id="_7-3-4-行为设计模式" tabindex="-1">7.3.4 行为设计模式 <a class="header-anchor" href="#_7-3-4-行为设计模式" aria-label="Permalink to &quot;7.3.4 行为设计模式&quot;">​</a></h3><h3 id="_7-3-5-应用举例" tabindex="-1">7.3.5 应用举例 <a class="header-anchor" href="#_7-3-5-应用举例" aria-label="Permalink to &quot;7.3.5 应用举例&quot;">​</a></h3>',44),t=[r];function h(n,d,s,c,_,u){return i(),l("div",null,t)}const m=a(o,[["render",h]]);export{b as __pageData,m as default};
